      "path": "src/modules/tasks/service.js",
      "content": "const projectsService = require('../projects/service');
const { randomUUID } = require('node:crypto');

function createTask(projectId) {
  const project = projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }
  const task = { id: randomUUID(), status: 'todo' };
  project.tasks.push(task);
  return task;
}

function getTasksByProjectId(projectId) {
  const project = projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }
  return project.tasks;
}

function updateTaskStatus(projectId, taskId, status) {
  const tasks = getTasksByProjectId(projectId);
  if (!tasks) {
    return null;
  }
  const task = tasks.find(task => task.id === taskId);
  if (!task) {
    return null;
  }
  task.status = status;
  return task;
}

module.exports = {
  createTask,
  getTasksByProjectId,
  updateTaskStatus,
};
